651â†’subquery_planner(PlannerGlobal *glob, Query *parse, PlannerInfo *parent_root,
   652â†’				 bool hasRecursion, double tuple_fraction,
   653â†’				 SetOperationStmt *setops)
   654â†’{
   655â†’	PlannerInfo *root;
   656â†’	List	   *newWithCheckOptions;
   657â†’	List	   *newHaving;
   658â†’	bool		hasOuterJoins;
   659â†’	bool		hasResultRTEs;
   660â†’	RelOptInfo *final_rel;
   661â†’	ListCell   *l;
   662â†’
   663â†’	/* Create a PlannerInfo data structure for this subquery */
   664â†’	root = makeNode(PlannerInfo);
   665â†’	root->parse = parse;
   666â†’	root->glob = glob;
   667â†’	root->query_level = parent_root ? parent_root->query_level + 1 : 1;
   668â†’	root->parent_root = parent_root;
   669â†’	root->plan_params = NIL;
   670â†’	root->outer_params = NULL;
   671â†’	root->planner_cxt = CurrentMemoryContext;
   672â†’	root->init_plans = NIL;
   673â†’	root->cte_plan_ids = NIL;
   674â†’	root->multiexpr_params = NIL;
   675â†’	root->join_domains = NIL;
   676â†’	root->eq_classes = NIL;
   677â†’	root->ec_merging_done = false;
   678â†’	root->last_rinfo_serial = 0;
   679â†’	root->all_result_relids =
   680â†’		parse->resultRelation ? bms_make_singleton(parse->resultRelation) : NULL;
   681â†’	root->leaf_result_relids = NULL;	/* we'll find out leaf-ness later */
   682â†’	root->append_rel_list = NIL;
   683â†’	root->row_identity_vars = NIL;
   684â†’	root->rowMarks = NIL;
   685â†’	memset(root->upper_rels, 0, sizeof(root->upper_rels));
   686â†’	memset(root->upper_targets, 0, sizeof(root->upper_targets));
   687â†’	root->processed_groupClause = NIL;
   688â†’	root->processed_distinctClause = NIL;
   689â†’	root->processed_tlist = NIL;
   690â†’	root->update_colnos = NIL;
   691â†’	root->grouping_map = NULL;
   692â†’	root->minmax_aggs = NIL;
   693â†’	root->qual_security_level = 0;
   694â†’	root->hasPseudoConstantQuals = false;
   695â†’	root->hasAlternativeSubPlans = false;
   696â†’	root->placeholdersFrozen = false;
   697â†’	root->hasRecursion = hasRecursion;
   698â†’	if (hasRecursion)
   699â†’		root->wt_param_id = assign_special_exec_param(root);
   700â†’	else
   701â†’		root->wt_param_id = -1;
   702â†’	root->non_recursive_path = NULL;
   703â†’	root->partColsUpdated = false;
   704â†’
   705â†’	/*
   706â†’	 * Create the top-level join domain.  This won't have valid contents until
   707â†’	 * deconstruct_jointree fills it in, but the node needs to exist before
   708â†’	 * that so we can build EquivalenceClasses referencing it.
   709â†’	 */
   710â†’	root->join_domains = list_make1(makeNode(JoinDomain));
   711â†’
   712â†’	/*
   713â†’	 * If there is a WITH list, process each WITH query and either convert it
   714â†’	 * to RTE_SUBQUERY RTE(s) or build an initplan SubPlan structure for it.
   715â†’	 */
   716â†’	if (parse->cteList)
   717â†’		SS_process_ctes(root);
   718â†’
   719â†’	/*
   720â†’	 * If it's a MERGE command, transform the joinlist as appropriate.
   721â†’	 */
   722â†’	transform_MERGE_to_join(parse);
   723â†’
   724â†’	/*
   725â†’	 * If the FROM clause is empty, replace it with a dummy RTE_RESULT RTE, so
   726â†’	 * that we don't need so many special cases to deal with that situation.
   727â†’	 */
   728â†’	replace_empty_jointree(parse);
   729â†’
   730â†’	/*
   731â†’	 * Look for ANY and EXISTS SubLinks in WHERE and JOIN/ON clauses, and try
   732â†’	 * to transform them into joins.  Note that this step does not descend
   733â†’	 * into subqueries; if we pull up any subqueries below, their SubLinks are
   734â†’	 * processed just before pulling them up.
   735â†’	 */
   736â†’	if (parse->hasSubLinks)
   737â†’		pull_up_sublinks(root);
   738â†’
   739â†’	/*
   740â†’	 * Scan the rangetable for function RTEs, do const-simplification on them,
   741â†’	 * and then inline them if possible (producing subqueries that might get
   742â†’	 * pulled up next).  Recursion issues here are handled in the same way as
   743â†’	 * for SubLinks.
   744â†’	 */
   745â†’	preprocess_function_rtes(root);
   746â†’
   747â†’	/*
   748â†’	 * Scan the rangetable for relations with virtual generated columns, and
   749â†’	 * replace all Var nodes in the query that reference these columns with
   750â†’	 * the generation expressions.  Recursion issues here are handled in the
   751â†’	 * same way as for SubLinks.
   752â†’	 */
   753â†’	parse = root->parse = expand_virtual_generated_columns(root);
   754â†’
   755â†’	/*
   756â†’	 * Check to see if any subqueries in the jointree can be merged into this
   757â†’	 * query.
   758â†’	 */
   759â†’	pull_up_subqueries(root);
   760â†’
   761â†’	/*
   762â†’	 * If this is a simple UNION ALL query, flatten it into an appendrel. We
   763â†’	 * do this now because it requires applying pull_up_subqueries to the leaf
   764â†’	 * queries of the UNION ALL, which weren't touched above because they
   765â†’	 * weren't referenced by the jointree (they will be after we do this).
   766â†’	 */
   767â†’	if (parse->setOperations)
   768â†’		flatten_simple_union_all(root);
   769â†’
   770â†’	/*
   771â†’	 * Survey the rangetable to see what kinds of entries are present.  We can
   772â†’	 * skip some later processing if relevant SQL features are not used; for
   773â†’	 * example if there are no JOIN RTEs we can avoid the expense of doing
   774â†’	 * flatten_join_alias_vars().  This must be done after we have finished
   775â†’	 * adding rangetable entries, of course.  (Note: actually, processing of
   776â†’	 * inherited or partitioned rels can cause RTEs for their child tables to
   777â†’	 * get added later; but those must all be RTE_RELATION entries, so they
   778â†’	 * don't invalidate the conclusions drawn here.)
   779â†’	 */
   780â†’	root->hasJoinRTEs = false;
   781â†’	root->hasLateralRTEs = false;
   782â†’	root->group_rtindex = 0;
   783â†’	hasOuterJoins = false;
   784â†’	hasResultRTEs = false;
   785â†’	foreach(l, parse->rtable)
   786â†’	{
   787â†’		RangeTblEntry *rte = lfirst_node(RangeTblEntry, l);
   788â†’
   789â†’		switch (rte->rtekind)
   790â†’		{
   791â†’			case RTE_RELATION:
   792â†’				if (rte->inh)
   793â†’				{
   794â†’					/*
   795â†’					 * Check to see if the relation actually has any children;
   796â†’					 * if not, clear the inh flag so we can treat it as a
   797â†’					 * plain base relation.
   798â†’					 *
   799â†’					 * Note: this could give a false-positive result, if the
   800â†’					 * rel once had children but no longer does.  We used to
   801â†’					 * be able to clear rte->inh later on when we discovered
   802â†’					 * that, but no more; we have to handle such cases as
   803â†’					 * full-fledged inheritance.
   804â†’					 */
   805â†’					rte->inh = has_subclass(rte->relid);
   806â†’				}
   807â†’				break;
   808â†’			case RTE_JOIN:
   809â†’				root->hasJoinRTEs = true;
